import{_ as a,o as t,c as o,ae as i}from"./chunks/framework.BD9pLfSD.js";const p=JSON.parse('{"title":"Deep Dive: The xB77 Autonomous Agent Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"docs/explanations/AGENT_DESIGN.md","filePath":"docs/explanations/AGENT_DESIGN.md"}'),n={name:"docs/explanations/AGENT_DESIGN.md"};function r(l,e,s,c,h,d){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="deep-dive-the-xb77-autonomous-agent-architecture" tabindex="-1">Deep Dive: The xB77 Autonomous Agent Architecture <a class="header-anchor" href="#deep-dive-the-xb77-autonomous-agent-architecture" aria-label="Permalink to &quot;Deep Dive: The xB77 Autonomous Agent Architecture&quot;">​</a></h1><h2 id="_1-philosophical-framework" tabindex="-1">1. Philosophical Framework <a class="header-anchor" href="#_1-philosophical-framework" aria-label="Permalink to &quot;1. Philosophical Framework&quot;">​</a></h2><p>The xB77 Agent is modeled after a corporate Chief Financial Officer (CFO). Its primary mandates are:</p><ol><li>Capital Preservation: Minimize loss and exposure.</li><li>Operational Continuity: Ensure liquidity is always available for tasks.</li><li>Information Asymmetry Management: Protect the corporate &quot;Alpha&quot; by utilizing privacy rails.</li></ol><h2 id="_2-the-decision-loop-scan-analyze-act" tabindex="-1">2. The Decision Loop (Scan-Analyze-Act) <a class="header-anchor" href="#_2-the-decision-loop-scan-analyze-act" aria-label="Permalink to &quot;2. The Decision Loop (Scan-Analyze-Act)&quot;">​</a></h2><h3 id="_2-1-the-sensory-layer-scan" tabindex="-1">2.1 The Sensory Layer (Scan) <a class="header-anchor" href="#_2-1-the-sensory-layer-scan" aria-label="Permalink to &quot;2.1 The Sensory Layer (Scan)&quot;">​</a></h3><p>The agent continuously listens to the blockchain via Helius Webhooks and internal MCP events. It monitors:</p><ul><li>Global Liquidity: Its balances across Fiat (Starpay), Public Crypto (Solana), and Private Crypto (Light/Shadow).</li><li>Market Signals: Current APY rates on protocols like Kamino.</li><li>Risk Signals: New sanctioned addresses or suspicious patterns in its interaction graph.</li></ul><h3 id="_2-2-the-strategy-engine-analyze" tabindex="-1">2.2 The Strategy Engine (Analyze) <a class="header-anchor" href="#_2-2-the-strategy-engine-analyze" aria-label="Permalink to &quot;2.2 The Strategy Engine (Analyze)&quot;">​</a></h3><p>When a payment request is received, the engine evaluates three variables:</p><ul><li>Privacy Requirement: Is the recipient a public entity or a strategic partner?</li><li>Compliance Risk: Does the destination trigger any Range Protocol flags?</li><li>Cost Efficiency: What are the current relayer fees vs. the value of privacy for this specific transaction?</li></ul><h3 id="_2-3-execution-modules-act" tabindex="-1">2.3 Execution Modules (Act) <a class="header-anchor" href="#_2-3-execution-modules-act" aria-label="Permalink to &quot;2.3 Execution Modules (Act)&quot;">​</a></h3><p>The agent selects the optimal &quot;Execution Path&quot;:</p><ul><li>Ghost Mode: Spawning ephemeral wallets for total decoupling.</li><li>Shielded Mode: Internal transfers within the private pool.</li><li>Optimized Mode: Moving idle funds back to Yield vaults if operational needs are met.</li></ul><h2 id="_3-memory-and-state-management" tabindex="-1">3. Memory and State Management <a class="header-anchor" href="#_3-memory-and-state-management" aria-label="Permalink to &quot;3. Memory and State Management&quot;">​</a></h2><p>Unlike stateless bots, xB77 agents maintain:</p><ul><li>Private Receipt Store: An encrypted SQLite database of all historical actions.</li><li>Identity Context: Its current ZK-Badge and credit line status.</li><li>Trust Scores: A dynamic local database of known-good vendors and high-risk entities.</li></ul><h2 id="_4-mcp-integration-model-context-protocol" tabindex="-1">4. MCP Integration (Model Context Protocol) <a class="header-anchor" href="#_4-mcp-integration-model-context-protocol" aria-label="Permalink to &quot;4. MCP Integration (Model Context Protocol)&quot;">​</a></h2><p>xB77 utilizes the Model Context Protocol to allow LLMs (Large Language Models) to interact with financial tools safely. The MCP layer acts as a &quot;Legal Buffer&quot;, ensuring that the LLM can propose actions, but the underlying xB77 SDK enforces the hard rules of compliance and privacy before any signature is generated.</p>',19)])])}const m=a(n,[["render",r]]);export{p as __pageData,m as default};
